        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with checkers pieces
        for i in range(3):
            for j in (1, 3, 5, 7):
                self.board[i][j] = Piece("white")
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                self.board[i][j] = Piece("black")

    def get_piece_at(self, x, y):
        return self.board[x][y]

    def move(self, from_x, from_y, to_x, to_y):
        piece = self.get_piece_at(from_x, from_y)
        if piece:
            self.board[from_x][from_y] = None
            self.board[to_x][to_y] = piece
            self.king_piece(to_x, to_y)

    def king_piece(self, x, y):
        if (x == 0 and self.board[x][y].color == "white") or (x == 7 and self.board[x][y].color == "black"):
            self.board[x][y].is_king = True

    def is_valid_move(self, from_x, from_y, to_x, to_y):
        piece = self.get_piece_at(from_x, from_y)
        if not piece:
            return False
        # Add more logic for capturing and standard moves
        return True
